"""Emission compliance tests for signet_eval_tool (auto-generated by pact)."""

from signet_eval_tool.signet_eval_tool import SignetEvalTool


class TestEmissionCompliance:
    """Verify signet_eval_tool emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_main_emits_events(self):
        """Method main emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = SignetEvalTool(event_handler=handler)
        try:
            obj.main()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for main'
        assert len(completed) >= 1, 'No completed/error event for main'
        assert invoked[0].get("pact_key") == "PACT:signet_eval_tool:main"
        assert isinstance(invoked[0].get("input_classification"), list)

