    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = SignetEvalTool(event_handler=handler)
        try:
            obj.main()
        except (TypeError, Exception):
            pass
        try:
            obj.parse_args()
        except (TypeError, Exception):
            pass
        try:
            obj.init_policy_file()
        except (TypeError, Exception):
            pass
        try:
            obj.load_policy()
        except (TypeError, Exception):
            pass
        try:
            obj.parse_hook_input()
        except (TypeError, Exception):
            pass
        try:
            obj.evaluate_request()
        except (TypeError, Exception):
            pass
        try:
            obj.match_rule_conditions()
        except (TypeError, Exception):
            pass
        try:
            obj.format_output()
        except (TypeError, Exception):
            pass
        try:
            obj.get_default_policy()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:signet_eval_tool:"), f"Bad pact_key: {key}"

